Method Name: helper.twoDimByteArrayToOne
Method Code:
    public byte[] twoDimByteArrayToOne(byte[][] bytes) {
        ByteArrayOutputStream out = new ByteArrayOutputStream();
        int row = 0;
        while (row < bytes.length) {
            try {
                out.write(bytes[row]);
            }
            catch (IOException e) {
                e.printStackTrace();
            }
            ++row;
        }
        return out.toByteArray();
    }

